import { join } from "node:path";
import { ROOT, readText, writeText } from "./shared.mjs";

// Generates public/tokens.css — the standalone, Tailwind-free token sheet
// served at https://www.gunjo.jp/tokens.css for environments where npm and
// CDNs are unavailable (Claude Artifacts, single-file HTML, sandboxes).
// Source of truth is src/globals.css (itself generated by sync-tokens.mjs),
// so the standalone sheet can never drift from the package tokens. (#678)

// Site-only art tokens (hero / color-story backgrounds) that have no meaning
// outside gunjo.jp. Everything else in :root / .dark ships.
const SITE_ONLY_PREFIXES = ["gunjo-", "dawn-", "kobicha-"];

const DECLARATION_PATTERN = /^\s*(--[a-z0-9-]+)\s*:\s*([^;]+);\s*$/;

/**
 * Extract the body of the first `<selector> {` block via brace counting.
 * Comments inside the block are tolerated as long as they contain no braces
 * (true for the generated source; a mismatch fails the sanity check below).
 */
export function extractBlock(css, selector) {
  const start = css.indexOf(`${selector} {`);
  if (start === -1) {
    throw new Error(
      `design:sync: standalone tokens: "${selector}" block not found in src/globals.css`
    );
  }
  const open = css.indexOf("{", start);
  let depth = 0;
  for (let i = open; i < css.length; i += 1) {
    if (css[i] === "{") depth += 1;
    if (css[i] === "}") {
      depth -= 1;
      if (depth === 0) return css.slice(open + 1, i);
    }
  }
  throw new Error(
    `design:sync: standalone tokens: unbalanced braces after "${selector}" in src/globals.css`
  );
}

function isSiteOnly(name) {
  return SITE_ONLY_PREFIXES.some((prefix) => name.startsWith(`--${prefix}`));
}

/**
 * Keep declarations (minus site-only tokens) and the blank lines between
 * groups so the emitted sheet stays readable; drop comments.
 */
function cleanBlock(blockBody) {
  const lines = [];
  let pendingBlank = false;
  for (const rawLine of blockBody.split("\n")) {
    const match = rawLine.match(DECLARATION_PATTERN);
    if (!match) {
      if (rawLine.trim() === "" && lines.length > 0) pendingBlank = true;
      continue;
    }
    const [, name, value] = match;
    if (isSiteOnly(name)) continue;
    if (pendingBlank) {
      lines.push("");
      pendingBlank = false;
    }
    lines.push(`    ${name}: ${value.trim()};`);
  }
  return lines;
}

function tokenNames(lines) {
  return new Set(
    lines
      .map((line) => line.match(/^\s*(--[a-z0-9-]+):/)?.[1])
      .filter(Boolean)
  );
}

/** Fail sync (and design:verify) loudly if the parse went quietly wrong. */
function assertSanity(rootLines, darkLines) {
  const required = [
    "--background",
    "--foreground",
    "--primary",
    "--success",
    "--warning",
    "--destructive",
    "--border",
    "--radius",
    "--shadow-sm",
  ];
  const rootNames = tokenNames(rootLines);
  const darkNames = tokenNames(darkLines);
  const missing = required.filter((name) => !rootNames.has(name));
  if (missing.length > 0) {
    throw new Error(
      `design:sync: standalone tokens: expected tokens missing from :root parse: ${missing.join(", ")}`
    );
  }
  if (!darkNames.has("--background") || darkNames.size < 20) {
    throw new Error(
      "design:sync: standalone tokens: .dark parse looks incomplete (missing --background or fewer than 20 tokens)"
    );
  }
}

const HEADER = `/*
 * GunjoUI デザイントークン（スタンドアロン版・Tailwind 不要の純 CSS）
 * GunjoUI design tokens, standalone. No build step required.
 *
 * 配布元: https://www.gunjo.jp/tokens.css
 * 使い方の解説: https://www.gunjo.jp/docs/no-npm
 * License: MIT (https://github.com/uixhero/gunjo)
 *
 * 値は "H S% L%" の HSL トリプレットです（hsl() で包んでいないのは、
 * 透明度を後から合成できるようにするためです）:
 *
 *   color: hsl(var(--primary));
 *   background: hsl(var(--primary) / 0.1);
 *
 * セマンティックトーンは 5 色（primary / info / success / warning /
 * destructive）。各色に subtle（淡い背景）・base（標準）・strong（濃い強調）
 * の 3 段と、専用の border があり、背景には -subtle、その上の文字には
 * -subtle-foreground のように、対になる foreground を組み合わせます。
 *
 * ダークモードは <html class="dark"> または <html data-theme="dark"> で
 * 切り替えます。OS 設定に追従させる場合は <head> にこの 1 行:
 *
 *   <script>if(matchMedia("(prefers-color-scheme: dark)").matches)document.documentElement.classList.add("dark")</script>
 *
 * 影は box-shadow: var(--shadow-md) のようにそのまま使えます。
 * --duration-* と --ease-* は transition / animation に使います。
 */
`;

const BASE_STYLES = `/* 最小のベーススタイル（Tailwind preflight の要点だけを純 CSS で再現） */
*,
::before,
::after {
    box-sizing: border-box;
    border-width: 0;
    border-style: solid;
    border-color: hsl(var(--border));
}

body {
    margin: 0;
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
    font-family: ui-sans-serif, system-ui, sans-serif, "Apple Color Emoji", "Segoe UI Emoji";
    background-color: hsl(var(--background));
    color: hsl(var(--foreground));
}
`;

export function buildStandaloneTokensCss({ root = ROOT } = {}) {
  const source = readText(join(root, "src", "globals.css"));
  const rootLines = cleanBlock(extractBlock(source, ":root"));
  const darkLines = cleanBlock(extractBlock(source, ".dark"));
  assertSanity(rootLines, darkLines);

  return [
    HEADER,
    `:root {\n${rootLines.join("\n")}\n}`,
    "",
    `.dark,\n[data-theme="dark"] {\n${darkLines.join("\n")}\n}`,
    "",
    BASE_STYLES,
  ].join("\n");
}

export function syncStandaloneTokens({ root = ROOT } = {}) {
  const outputPath = join(root, "public", "tokens.css");
  writeText(outputPath, buildStandaloneTokensCss({ root }));
  console.log(
    "design:sync: Updated public/tokens.css from src/globals.css (standalone tokens)"
  );
}
